// frontend/src/components/Dashboard/ProfitChart.js
import React, { useRef, useEffect } from 'react';
import {
  Paper,
  Typography,
  Box,
  Skeleton,
  useTheme
} from '@mui/material';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
} from 'chart.js';
import { Line } from 'react-chartjs-2';
import { TrendingUp } from '@mui/icons-material';

// Registrar componentes do Chart.js
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const ProfitChart = ({ data, loading }) => {
  const theme = useTheme();
  const chartRef = useRef();

  const formatCurrency = (value) => {
    if (value === null || value === undefined) return '$0.00';
    return `$${parseFloat(value).toFixed(2)}`;
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: '2-digit'
    });
  };

  // Verificar se data é um array
  const isDataArray = Array.isArray(data);

  // Preparar dados para o gráfico
  const chartData = {
    labels: isDataArray ? data.map(item => formatDate(item.date)) : [],
    datasets: [
      {
        label: 'PnL Acumulado',
        data: isDataArray ? data.map(item => item.cumulative_pnl) : [],
        borderColor: theme.palette.primary.main,
        backgroundColor: `${theme.palette.primary.main}20`,
        borderWidth: 3,
        fill: true,
        tension: 0.4,
        pointBackgroundColor: theme.palette.primary.main,
        pointBorderColor: theme.palette.background.paper,
        pointBorderWidth: 2,
        pointRadius: 4,
        pointHoverRadius: 6,
        pointHoverBackgroundColor: theme.palette.primary.main,
        pointHoverBorderColor: theme.palette.background.paper,
        pointHoverBorderWidth: 3
      }
    ]
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    interaction: {
      intersect: false,
      mode: 'index'
    },
    plugins: {
      legend: {
        display: false
      },
      tooltip: {
        backgroundColor: theme.palette.background.paper,
        titleColor: theme.palette.text.primary,
        bodyColor: theme.palette.text.primary,
        borderColor: theme.palette.divider,
        borderWidth: 1,
        cornerRadius: 8,
        displayColors: false,
        callbacks: {
          label: function(context) {
            return `PnL: ${formatCurrency(context.parsed.y)}`;
          }
        }
      }
    },
    scales: {
      x: {
        grid: {
          color: theme.palette.divider,
          drawBorder: false
        },
        ticks: {
          color: theme.palette.text.secondary,
          font: {
            size: 12
          },
          maxTicksLimit: 8
        }
      },
      y: {
        grid: {
          color: theme.palette.divider,
          drawBorder: false
        },
        ticks: {
          color: theme.palette.text.secondary,
          font: {
            size: 12
          },
          callback: function(value) {
            return formatCurrency(value);
          }
        }
      }
    },
    elements: {
      point: {
        hoverRadius: 8
      }
    }
  };

  if (loading) {
    return (
      <Paper sx={{ p: 3, height: 400 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
          <Skeleton variant="circular" width={24} height={24} sx={{ mr: 1 }} />
          <Skeleton variant="text" width={200} height={32} />
        </Box>
        <Skeleton variant="rectangular" width="100%" height={300} sx={{ borderRadius: 1 }} />
      </Paper>
    );
  }

  if (!data || data.length === 0) {
    return (
      <Paper sx={{ p: 3, height: 400 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 3 }}>
          <TrendingUp color="primary" />
          Curva de Lucro
        </Typography>
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            height: 300,
            bgcolor: 'background.default',
            borderRadius: 1,
            border: `1px dashed ${theme.palette.divider}`
          }}
        >
          <Typography variant="body1" color="text.secondary">
            Nenhum dado de lucro disponível
          </Typography>
        </Box>
      </Paper>
    );
  }

  const currentPnL = data[data.length - 1]?.cumulative_pnl || 0;
  const previousPnL = data.length > 1 ? data[data.length - 2]?.cumulative_pnl || 0 : 0;
  const pnlChange = currentPnL - previousPnL;
  const pnlChangePercent = previousPnL !== 0 ? ((pnlChange / Math.abs(previousPnL)) * 100) : 0;

  return (
    <Paper sx={{ p: 3, height: 400 }}>
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 3 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <TrendingUp color="primary" />
          Curva de Lucro
        </Typography>

        <Box sx={{ textAlign: 'right' }}>
          <Typography variant="h6" sx={{ color: currentPnL >= 0 ? 'success.main' : 'error.main' }}>
            {formatCurrency(currentPnL)}
          </Typography>
          <Typography 
            variant="caption" 
            sx={{ 
              color: pnlChange >= 0 ? 'success.main' : 'error.main',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'flex-end',
              gap: 0.5
            }}
          >
            {pnlChange >= 0 ? '+' : ''}{formatCurrency(pnlChange)}
            {pnlChangePercent !== 0 && (
              <span>
                ({pnlChangePercent >= 0 ? '+' : ''}{pnlChangePercent.toFixed(2)}%)
              </span>
            )}
          </Typography>
        </Box>
      </Box>

      <Box sx={{ height: 300, position: 'relative' }}>
        <Line ref={chartRef} data={chartData} options={chartOptions} />
      </Box>
    </Paper>
  );
};

export default ProfitChart;
